import{_ as a,C as o,o as n,c as s,a3 as i,E as l,w as d,j as t}from"./chunks/framework.BVmBWEBf.js";const u="/versions/v0.10.0/screens/macros/macro_aftertouch.png",v=JSON.parse('{"title":"Channel Aftertouch","description":"","frontmatter":{"title":"Channel Aftertouch","pageClass":"macro-doc"},"headers":[],"relativePath":"macros/channel-aftertouch.md","filePath":"macros/channel-aftertouch.md"}'),c={name:"macros/channel-aftertouch.md"};function h(m,e,p,g,f,b){const r=o("ManualRelated");return n(),s("div",null,[e[1]||(e[1]=i('<h1 id="channel-aftertouch" tabindex="-1">Channel Aftertouch <a class="header-anchor" href="#channel-aftertouch" aria-label="Permalink to &quot;Channel Aftertouch&quot;">​</a></h1><p><strong>Firmware menu name:</strong> AT</p><p>Send MIDI channel aftertouch (pressure).</p><p><img src="'+u+'" alt="Channel Aftertouch macro" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Use <strong>AT</strong> (channel pressure) to drive aftertouch from a knob. MSB/LSB select the pressure controller pair when required by the target.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Mode</td><td>—</td><td>Macro output type. Change this to switch between MIDI, internal routing, and CV16 targets.</td></tr><tr><td>MSB</td><td>0 – 127</td><td>Most significant byte. For <strong>CC</strong> and <strong>CC14</strong> this is the control number; for <strong>NRPN</strong> / <strong>RPN</strong> it is the parameter number MSB.</td></tr><tr><td>LSB</td><td>0 – 127</td><td>Least significant byte. For <strong>CC14</strong> this completes the 14-bit controller number; for <strong>NRPN</strong> / <strong>RPN</strong> it is the parameter number LSB.</td></tr><tr><td>Minimum</td><td>Mode-specific</td><td>Value sent when the knob is at minimum travel. Units follow the target (MIDI 0–127, 14-bit 0–16383, device parameter native range, CV volts, LFO %, etc.).</td></tr><tr><td>Maximum</td><td>Mode-specific</td><td>Value sent when the knob is at maximum travel. Must be greater than or equal to <strong>Minimum</strong>.</td></tr><tr><td>Channel</td><td>Global, 1 – 16</td><td>MIDI channel for outgoing messages. <strong>Global</strong> uses the project&#39;s global channel setting.</td></tr><tr><td>Invert</td><td>True / False</td><td>When <strong>True</strong>, knob clockwise motion maps to decreasing values (minimum ↔ maximum swapped).</td></tr><tr><td>Outputs</td><td>USB / DIN / combos</td><td>Which physical MIDI outputs carry this macro: USB, <strong>Out 1</strong>, <strong>Out 2</strong>, or combined masks.</td></tr></tbody></table></div><h2 id="midi-outputs" tabindex="-1">MIDI outputs <a class="header-anchor" href="#midi-outputs" aria-label="Permalink to &quot;MIDI outputs&quot;">​</a></h2><p>The <strong>Outputs</strong> field selects one of these port combinations:</p><ul><li>None</li><li>USB</li><li>Out 1</li><li>USB + Out 1</li><li>Out 2</li><li>USB + Out 2</li><li>Out 1 + Out 2</li><li>USB + Out 1 + Out 2</li></ul>',11)),l(r,{title:"Related topics"},{default:d(()=>[...e[0]||(e[0]=[t("ul",null,[t("li",null,[t("a",{href:"/versions/v0.10.0/macros/"},"Macros overview")]),t("li",null,[t("a",{href:"/versions/v0.10.0/macros/setting-up-macros"},"Setting up macros")]),t("li",null,[t("a",{href:"/versions/v0.10.0/concepts/modulation"},"Modulation")])],-1)])]),_:1})])}const M=a(c,[["render",h]]);export{v as __pageData,M as default};
